() => {
  const url = new URL(location.href);
  const utms = {};
  for (const [k, v] of url.searchParams.entries()) {
    if (k.startsWith('utm')) utms[k] = v;
  }

  // Check if Klaviyo JS has picked up UTMs (it stores them in _klx or cookies)
  const cookies = {};
  document.cookie.split(';').forEach(c => {
    const [k, v] = c.trim().split('=');
    if (k) cookies[k] = v;
  });

  // Check localStorage for klaviyo UTM storage
  const lsKeys = {};
  try {
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && (k.includes('utm') || k.includes('kla') || k.includes('klaviyo'))) {
        lsKeys[k] = localStorage.getItem(k);
      }
    }
  } catch(e) {}

  // Find the Klaviyo form
  const form = document.querySelector('[data-form-id], .klaviyo-form, [class*="klaviyo"], form');
  const formInfo = form ? {
    tag: form.tagName,
    id: form.id,
    dataFormId: form.getAttribute('data-form-id'),
    classes: form.className.slice(0,100),
    action: form.action || null
  } : null;

  // Check all script tags for klaviyo init
  const scripts = [...document.querySelectorAll('script[src]')]
    .map(s => s.src)
    .filter(s => s.includes('klaviyo') || s.includes('kla'));

  return { 
    pageUrl: location.href,
    utmsInUrl: utms,
    utmCount: Object.keys(utms).length,
    klaviyoCookies: Object.entries(cookies).filter(([k]) => k.includes('kla') || k.includes('_kl')).slice(0,10),
    localStorageUtms: lsKeys,
    formFound: formInfo,
    klaviyoScripts: scripts.slice(0,5)
  };
}

() => {
  // Find email input
  const emailInput = document.querySelector('input[type="email"], input[name="email"], input[placeholder*="mail" i]');
  const submitBtn = document.querySelector('button[type="submit"], input[type="submit"], button[class*="submit"], .needsclick');

  return {
    emailInputFound: !!emailInput,
    emailInputSelector: emailInput ? emailInput.outerHTML.slice(0,200) : null,
    submitBtnFound: !!submitBtn,
    submitBtnText: submitBtn ? submitBtn.textContent.trim().slice(0,50) : null,
    allInputs: [...document.querySelectorAll('input')].map(i => ({type: i.type, name: i.name, placeholder: i.placeholder, classes: i.className.slice(0,80)})).slice(0,10),
    allButtons: [...document.querySelectorAll('button')].map(b => ({text: b.textContent.trim().slice(0,40), type: b.type, classes: b.className.slice(0,60)})).slice(0,10),
    pageTitle: document.title,
    bodySnippet: document.body.innerText.slice(0, 500)
  };
}

